const countNeighbors = (grid: Grid, row: number, col: number): number => {
  let count = 0;
  for (let r = row - 1; r <= row + 1; r++) {
    for (let c = col - 1; c <= col + 1; c++) {
      if (r === row && c === col) continue;
      if (r >= 0 && r < grid.length && c >= 0 && c < grid[0].length && grid[r][c]) {
        count++;
      }
    }
  }
  return count;
};

export function nextGeneration(grid: Grid): Grid {
  if (grid.length === 0) {
    return [];
  }

  return grid.map((row, rowIdx) =>
    row.map((cell, colIdx) => {
      const neighbors = countNeighbors(grid, rowIdx, colIdx);
      if (cell && neighbors < 2) {
        return false;
      }
      if (cell && (neighbors === 2 || neighbors === 3)) {
        return true;
      }
      if (!cell && neighbors === 3) {
        return true;
      }
      return cell;
    })
  );
}
```

