const willSurviveToNextGeneration = (isAlive: boolean, neighbors: number): boolean => {
  if (isAlive && neighbors < 2) {
    return false; // Underpopulation rule
  }
  if (isAlive && (neighbors === 2 || neighbors === 3)) {
    return true; // Survival rule
  }
  if (!isAlive && neighbors === 3) {
    return true; // Reproduction rule
  }
  return isAlive; // Default: cell stays as is
};

export function nextGeneration(grid: Grid): Grid {
  if (grid.length === 0) {
    return [];
  }

  return grid.map((row, rowIdx) =>
    row.map((cell, colIdx) => {
      const neighbors = countNeighbors(grid, rowIdx, colIdx);
      return willSurviveToNextGeneration(cell, neighbors);
    })
  );
}

